import{_ as e,o as i,c as l,a0 as t}from"./chunks/framework.CED9SG98.js";const _=JSON.parse('{"title":"数据技能体系（七层结构）","description":"Eason 数据技能知识库的总览，涵盖从基础技能到领域实践的完整数据价值链","frontmatter":{"type":"Concept","title":"数据技能体系（七层结构）","description":"Eason 数据技能知识库的总览，涵盖从基础技能到领域实践的完整数据价值链","source_url":"n/a","source_title":"数据技能 MOC","source_platform":"内部","ingest_date":"2026-07-12T00:00:00.000Z","access_date":"2026-07-12T00:00:00.000Z","tags":["数据技能","数据产品经理","知识体系","面试"],"status":"compiled","review_count":0,"last_review":"2026-07-12T00:00:00.000Z","next_review":"2026-07-13T00:00:00.000Z"},"headers":[],"relativePath":"wiki/concepts/DataSkills.md","filePath":"wiki/concepts/DataSkills.md"}'),o={name:"wiki/concepts/DataSkills.md"};function r(h,a,n,s,d,c){return i(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="数据技能体系-七层结构" tabindex="-1">数据技能体系（七层结构） <a class="header-anchor" href="#数据技能体系-七层结构" aria-label="Permalink to &quot;数据技能体系（七层结构）&quot;">​</a></h1><h2 id="总览" tabindex="-1">总览 <a class="header-anchor" href="#总览" aria-label="Permalink to &quot;总览&quot;">​</a></h2><p>本页是 Eason 数据技能知识库的总览导航，涵盖从基础技能到领域实践的完整数据价值链。</p><h2 id="七层结构" tabindex="-1">七层结构 <a class="header-anchor" href="#七层结构" aria-label="Permalink to &quot;七层结构&quot;">​</a></h2><h3 id="_00-基础技能层" tabindex="-1">00-基础技能层 <a class="header-anchor" href="#_00-基础技能层" aria-label="Permalink to &quot;00-基础技能层&quot;">​</a></h3><p>数据从业者的通用底层能力，包括 SQL 查询、Python 数据处理、AI 素养以及数学与统计学基础。这一层是向上攀登的根基。</p><h3 id="_01-数据认知层" tabindex="-1">01-数据认知层 <a class="header-anchor" href="#_01-数据认知层" aria-label="Permalink to &quot;01-数据认知层&quot;">​</a></h3><p>建立对数据的系统认知，涵盖数据类型与结构、数据建模方法、数据生命周期、数据质量管理以及主数据与元数据管理。</p><h3 id="_02-数据工程层" tabindex="-1">02-数据工程层 <a class="header-anchor" href="#_02-数据工程层" aria-label="Permalink to &quot;02-数据工程层&quot;">​</a></h3><p>数据价值链的基建层，聚焦数据采集、存储系统、数据处理、数据治理、数据架构、数据可观测性等核心工程主题。</p><h3 id="_03-数据分析层" tabindex="-1">03-数据分析层 <a class="header-anchor" href="#_03-数据分析层" aria-label="Permalink to &quot;03-数据分析层&quot;">​</a></h3><p>将数据转化为洞察的核心方法论层，包括指标体系、描述/诊断/预测/分析方法、统计学基础、实验设计与因果推断。</p><h3 id="_04-数据应用层" tabindex="-1">04-数据应用层 <a class="header-anchor" href="#_04-数据应用层" aria-label="Permalink to &quot;04-数据应用层&quot;">​</a></h3><p>数据价值的直接变现层，涵盖数据产品设计、数据可视化、数据驱动决策、AB 测试、增长黑客等内容。</p><h3 id="_05-数据战略层" tabindex="-1">05-数据战略层 <a class="header-anchor" href="#_05-数据战略层" aria-label="Permalink to &quot;05-数据战略层&quot;">​</a></h3><p>从组织视角看待数据，包含数据战略规划、数据组织架构、数据治理体系、数据文化与伦理合规。</p><h3 id="_06-领域实践层" tabindex="-1">06-领域实践层 <a class="header-anchor" href="#_06-领域实践层" aria-label="Permalink to &quot;06-领域实践层&quot;">​</a></h3><p>垂直行业和业务场景中的数据实践，覆盖互联网、金融、零售电商、SaaS、智能制造等领域。</p><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to &quot;学习路径建议&quot;">​</a></h2><h3 id="入门路线" tabindex="-1">入门路线 <a class="header-anchor" href="#入门路线" aria-label="Permalink to &quot;入门路线&quot;">​</a></h3><ol><li>先建立整体框架：数据认知</li><li>夯实工具技能：基础技能（重点 SQL 与 Python）</li><li>理解数据如何流动：数据工程</li><li>尝试第一次数据分析：数据分析</li></ol><h3 id="进阶路线" tabindex="-1">进阶路线 <a class="header-anchor" href="#进阶路线" aria-label="Permalink to &quot;进阶路线&quot;">​</a></h3><ol><li>深耕工程能力：数据工程（深入数据治理、Lakehouse）</li><li>精通分析方法论：数据分析（统计推断、实验设计）</li><li>掌握数据产品化思维：数据应用</li><li>拓展战略视野：数据战略</li></ol><h3 id="实战路线" tabindex="-1">实战路线 <a class="header-anchor" href="#实战路线" aria-label="Permalink to &quot;实战路线&quot;">​</a></h3><ol><li>选定目标行业：领域实践</li><li>结合业务场景做完整项目</li><li>用数据应用方法验证效果（AB 测试、指标体系监控）</li><li>复盘沉淀为个人案例库</li></ol><h2 id="面试高频考点" tabindex="-1">面试高频考点 <a class="header-anchor" href="#面试高频考点" aria-label="Permalink to &quot;面试高频考点&quot;">​</a></h2><ul><li>OSM模型</li><li>维度建模</li><li>数据仓库分层架构</li><li>指标体系</li><li>实验与因果推断</li><li>因果vs相关</li><li>数据治理框架</li><li>湖仓一体(Lakehouse)</li><li>决策框架</li><li>标签与用户画像</li><li>高级SQL</li></ul><h1 id="citations" tabindex="-1">Citations <a class="header-anchor" href="#citations" aria-label="Permalink to &quot;Citations&quot;">​</a></h1><ul><li>来源: 第二大脑 / 2-Areas/数据技能/数据技能 MOC.md</li></ul>',29)])])}const p=e(o,[["render",r]]);export{_ as __pageData,p as default};
